external_knowledge:
- 'Above 28' refers to the age group of users older than 28 years; 
- 'Bachelor’s Degree' in 'Engineering' is a specific educational background; 
- 'Urban' settlement refers to users living in city areas; 
- '>3' social media usage suggests frequent use; 
- 'Male' indicates the gender; 
- 'High' income bracket signifies a higher earnings category.

sql:
SELECT u.income_bracket, COUNT(*) AS user_count
FROM users u
WHERE u.education = (
    SELECT education_name FROM educations WHERE education_id = 1
) AND u.field_of_study = (
    SELECT field_name FROM fields_of_study WHERE field_id = 1
) AND u.age_group = (
    SELECT age_group_name FROM age_groups WHERE age_group_id = 1
)
GROUP BY u.income_bracket
ORDER BY user_count DESC
LIMIT 3;

SELECT age_groups.age_group_name, (age_groups.min_age + age_groups.max_age) / 2 AS average_age
FROM age_groups
GROUP BY age_groups.age_group_name;

SELECT social_media_name, AVG(average_daily_usage_minutes) AS Average_Usage_Minutes
FROM social_media_usage
GROUP BY social_media_name;

SELECT COUNT(u.user_id) AS TotalUsers, AVG(q.qol) AS AverageQualityOfLife
FROM users u
LEFT JOIN quality_of_life q ON u.user_id = q.user_id;
